ALTER TABLE emission_project_task ADD COLUMN IF NOT EXISTS assignee_id varchar(100), ADD COLUMN IF NOT EXISTS task_type varchar(40), ADD COLUMN IF NOT EXISTS priority varchar(20) NOT NULL DEFAULT 'NORMAL', ADD COLUMN IF NOT EXISTS target_url varchar(300), ADD COLUMN IF NOT EXISTS updated_at timestamp NOT NULL DEFAULT current_timestamp;
UPDATE emission_project_task t SET assignee_id=coalesce(t.assignee_id,p.owner_name),task_type=coalesce(t.task_type,t.task_code),target_url=coalesce(t.target_url,CASE t.task_code WHEN 'BASIC_INFO' THEN '/emission/project/detail' WHEN 'ACTIVITY_DATA' THEN '/emission/data_input' WHEN 'CALCULATION' THEN '/emission/result' WHEN 'VERIFICATION' THEN '/emission/validate' WHEN 'APPROVAL' THEN '/emission/validate?tab=approval' WHEN 'REPORT' THEN '/emission/report_submit' END),priority=CASE WHEN t.due_date<current_date THEN 'URGENT' WHEN t.due_date<=current_date+3 THEN 'HIGH' ELSE t.priority END FROM emission_project_registry p WHERE p.project_id=t.project_id;
